function tokenPolicyRuleMatches(rule: TokenPolicyRule, input: TokenPolicyInput): boolean {
  if (rule.principalProvider === "fly_machine") {
    return input.principal.provider === "fly_machine"
      ? flyMachineTokenPolicyAdapter.matches(rule, {
